## 🐛 Bug Report

If you define multiple print areas like so:

```js
await workbook.xlsx.readFile(path.resolve(baseRuta, 'excel.xlsx'));
  const worksheet = workbook.getWorksheet('Sheet');
 
  worksheet.pageSetup.printArea = 'A1:Q46&&A48:Q93&&A95:Q140';
// ...
  const buffer = workbook.xlsx.writeBuffer();
// send file to browser for download
```

When you open the file in excel 365, you only see the last print area defined, that is, `A95:Q140`

I found that it happens because Exceljs defines multiple print areas (i.e. multiple defined names), but Excel expects a single print area with a ranges array, so after patching the library to produce a print area with the following structure, it worked correctly:

```js
{
  name: '_xlnm.Print_Area',
  ranges: [
    'Sheet!$A$1:$Q$46',
    'Sheet!$A$48:$Q$93',
    'Sheet!$A$95:$Q$140'
  ],
  localSheetId: 0
}
```

The patch:

```
diff --git a/node_modules/exceljs/lib/xlsx/xform/book/workbook-xform.js b/node_modules/exceljs/lib/xlsx/xform/book/workbook-xform.js
index 5c10a58..e0cb85d 100644
--- a/node_modules/exceljs/lib/xlsx/xform/book/workbook-xform.js
+++ b/node_modules/exceljs/lib/xlsx/xform/book/workbook-xform.js
@@ -42,15 +42,16 @@ class WorkbookXform extends BaseXform {
     let index = 0; // sheets is sparse array - calc index manually
     model.sheets.forEach(sheet => {
       if (sheet.pageSetup && sheet.pageSetup.printArea) {
-        sheet.pageSetup.printArea.split('&&').forEach(printArea => {
-          const printAreaComponents = printArea.split(':');
-          const definedName = {
-            name: '_xlnm.Print_Area',
-            ranges: [`'${sheet.name}'!$${printAreaComponents[0]}:$${printAreaComponents[1]}`],
-            localSheetId: index,
-          };
-          printAreas.push(definedName);
-        });
+        const definedName = {
+          name: '_xlnm.Print_Area',
+          ranges: sheet.pageSetup.printArea.split('&&').map(printArea => {
+            const printAreaComponents = printArea.split(':');
+        
+            return [`'${sheet.name}'!$${printAreaComponents[0]}:$${printAreaComponents[1]}`]
+          }),
+          localSheetId: index,
+        };
+        printAreas.push(definedName);
